--
-- Name: work_order_transfer_request; Type: TABLE; Schema: public; Owner: energy_user
--

CREATE TABLE public.work_order_transfer_request (
    id bigint NOT NULL,
    work_order_id bigint NOT NULL,
    requester_personnel_id bigint NOT NULL,
    reason character varying(500) NOT NULL,
    status character varying(32) DEFAULT 'PENDING'::character varying NOT NULL,
    reviewer_username character varying(64),
    new_personnel_id bigint,
    review_note character varying(500),
    requested_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    reviewed_at timestamp without time zone,
    CONSTRAINT ck_transfer_request_status CHECK (((status)::text = ANY ((ARRAY['PENDING'::character varying, 'APPROVED'::character varying, 'REJECTED'::character varying])::text[])))
);


ALTER TABLE public.work_order_transfer_request OWNER TO energy_user;

