    personnel_id bigint,
    role character varying(32) DEFAULT 'PRIMARY'::character varying NOT NULL,
    assigned_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    released_at timestamp without time zone,
    note character varying(255),
    status character varying(16) DEFAULT 'ACTIVE'::character varying NOT NULL,
    CONSTRAINT ck_assignment_status CHECK (((status)::text = ANY ((ARRAY['ACTIVE'::character varying, 'RELEASED'::character varying, 'TRANSFERRED'::character varying])::text[])))
);


